DROP TABLE IF EXISTS `handover_patient`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `handover_patient` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `handover_id` bigint NOT NULL COMMENT '交班ID',
  `visit_id` bigint NOT NULL COMMENT '就诊ID',
  `patient_id` bigint NOT NULL COMMENT '患者ID',
  `filter_reason` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '筛选原因（NEW_ADMISSION/LEVEL1_NURSING/BOTH）',
  `bed_no` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '床位号',
  `patient_name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '患者姓名',
  `gender` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '性别',
  `age` int NOT NULL COMMENT '年龄',
  `diagnosis` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '主诊断（从诊断子表获取is_main=1）',
  `vitals` text COLLATE utf8mb4_unicode_ci COMMENT '生命体征（可编辑）',
  `current_condition` text COLLATE utf8mb4_unicode_ci COMMENT '目前情况（含前12h临时医嘱，可编辑）',
  `observation_items` text COLLATE utf8mb4_unicode_ci COMMENT '需观察项（可编辑）',
  `mews_score` int DEFAULT NULL COMMENT 'MEWS评分',
  `braden_score` int DEFAULT NULL COMMENT 'Braden评分',
  `fall_risk` int DEFAULT NULL COMMENT '跌倒风险评分',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_handover_id` (`handover_id`),
  KEY `idx_visit_id` (`visit_id`),
  KEY `idx_filter_reason` (`filter_reason`)
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='交班患者明细表';
/*!40101 SET character_set_client = @saved_cs_client */;

