--
-- Table structure for table `interface_config`
--

DROP TABLE IF EXISTS `interface_config`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `interface_config` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `config_code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置编码，唯一标识',
  `config_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置名称',
  `system` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '三方系统（HIS/移动护理/CDR/其他）',
  `mode` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '接口模式（PULL拉取/PUSH推送）',
  `protocol` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '通讯协议（HTTP/HTTPS/WEBSOCKET）',
  `api_protocol` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '接口协议（REST/SOAP/HL7/FHIR）',
  `method` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '请求方法（GET/POST/PUT/DELETE）',
  `url` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '接口地址',
  `data_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '数据类型（科室/医护/患者/诊断/医嘱等）',
  `sync_mode` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'MANUAL' COMMENT '同步模式（MANUAL手动/SCHEDULED定时/ON_DEMAND按需）',
  `sync_schedule` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '定时规则（Cron表达式）',
  `sync_order` int DEFAULT NULL COMMENT '定时同步执行顺序，NULL表示不参与定时同步',
  `request_template` text COLLATE utf8mb4_unicode_ci COMMENT '请求模板（JSON格式）',
  `auth_type` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'NONE' COMMENT '认证方式（NONE/BASIC/BEARER/API_KEY）',
  `auth_config` json DEFAULT NULL COMMENT '认证配置（JSON格式）',
  `retry_interval` int DEFAULT '5' COMMENT '重试间隔（秒）',
  `max_retries` int DEFAULT '3' COMMENT '最大重试次数',
  `on_failure` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'ALERT' COMMENT '失败处理（STOP停止/SKIP跳过/ALERT告警）',
  `sync_time_field` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'HIS时间字段名',
  `sync_time_param_start` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'startTime' COMMENT '同步起始时间参数名',
  `sync_time_param_end` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'endTime' COMMENT '同步结束时间参数名',
  `dept_param` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '科室参数名，如 arg0，NULL 表示不需要科室参数',
  `sync_time_format` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'yyyy-MM-dd HH:mm:ss' COMMENT 'HIS时间格式',
  `first_sync_days` int DEFAULT '30' COMMENT '首次同步天数',
  `incremental_sync_hours` int DEFAULT '24' COMMENT '增量同步小时数',
  `last_sync_time` datetime DEFAULT NULL COMMENT '上次成功同步时间',
  `last_sync_status` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '上次同步状态',
  `last_sync_count` int DEFAULT NULL COMMENT '上次同步记录数',
  `is_first_sync` tinyint(1) DEFAULT '1' COMMENT '是否首次同步',
  `enabled` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `soap_action` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'SOAP Action',
  `soap_namespace` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'SOAP命名空间',
  `soap_params` json DEFAULT NULL COMMENT 'SOAP参数配置',
  `description` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '配置说明',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_config_code` (`config_code`),
  KEY `idx_system` (`system`),
  KEY `idx_data_type` (`data_type`),
  KEY `idx_enabled` (`enabled`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='接口配置主表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `interface_config`
--

