DROP TABLE IF EXISTS `shift_handover`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `shift_handover` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `dept_id` bigint NOT NULL COMMENT '科室ID',
  `dept_name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '科室名称',
  `handover_date` date NOT NULL COMMENT '交班日期',
  `shift` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '班次（白班/夜班）',
  `from_doctor_id` bigint NOT NULL COMMENT '交班医生ID',
  `from_doctor_name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '交班医生姓名',
