  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'DRAFT' COMMENT '状态（DRAFT/PENDING/TRANSFERRING/COMPLETED）',
  `summary_json` json DEFAULT NULL COMMENT '科室统计信息',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `reject_reason` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `handover_no` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '交班编号',
  PRIMARY KEY (`id`),
  UNIQUE KEY `handover_no` (`handover_no`),
  KEY `idx_dept_id` (`dept_id`),
  KEY `idx_handover_date` (`handover_date`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=39 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='交班主表';
