  `sync_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '同步类型（FIRST首次/INCREMENTAL增量/MANUAL手动）',
  `sync_start_time` datetime NOT NULL COMMENT '同步查询起始时间',
  `sync_end_time` datetime NOT NULL COMMENT '同步查询结束时间',
  `actual_start_time` datetime NOT NULL COMMENT '实际执行开始时间',
  `actual_end_time` datetime NOT NULL COMMENT '实际执行结束时间',
  `sync_status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '同步状态（SUCCESS/FAILED/PARTIAL）',
  `record_count` int DEFAULT NULL COMMENT '同步记录数',
  `success_count` int DEFAULT NULL COMMENT '成功写入数',
  `fail_count` int DEFAULT NULL COMMENT '失败数',
  `skip_count` int DEFAULT '0' COMMENT '跳过记录数',
  `update_count` int DEFAULT '0' COMMENT '更新记录数',
  `insert_count` int DEFAULT '0' COMMENT '新增记录数',
  `error_message` text COLLATE utf8mb4_unicode_ci COMMENT '错误信息',
  `request_data` text COLLATE utf8mb4_unicode_ci COMMENT '请求数据（JSON）',
  `response_sample` text COLLATE utf8mb4_unicode_ci COMMENT '响应数据样例',
  `duration_ms` int DEFAULT NULL COMMENT '执行耗时（毫秒）',
  `operator_id` bigint DEFAULT NULL COMMENT '操作人ID',
  `operator_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '操作人姓名',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_config_id` (`config_id`),
  KEY `idx_config_code` (`config_code`),
  KEY `idx_sync_status` (`sync_status`),
  KEY `idx_actual_start_time` (`actual_start_time`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=258 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='同步记录表';
