--
-- Table structure for table `transfer_record`
--

DROP TABLE IF EXISTS `transfer_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `transfer_record` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `visit_id` bigint NOT NULL COMMENT '就诊ID',
  `visit_no` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '就诊编码（HIS的code_ent）',
  `patient_id` bigint NOT NULL COMMENT '患者ID',
  `patient_no` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '患者编码（HIS的code_pat）',
  `from_dept_id` bigint DEFAULT NULL COMMENT '转出科室ID',
  `from_dept_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '转出科室名称',
  `to_dept_id` bigint NOT NULL COMMENT '转入科室ID',
  `to_dept_name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '转入科室名称',
  `transfer_time` datetime NOT NULL COMMENT '转科时间',
  `transfer_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '转科类型（入科/转出/转入）',
  `reason` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '转科原因',
  `sync_time` datetime NOT NULL COMMENT '最后同步时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_visit_id` (`visit_id`),
  KEY `idx_visit_no` (`visit_no`),
  KEY `idx_patient_id` (`patient_id`),
  KEY `idx_to_dept_id` (`to_dept_id`),
  KEY `idx_transfer_time` (`transfer_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='转科记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

