--
-- Table structure for table `visit`
--

DROP TABLE IF EXISTS `visit`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `visit` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `visit_no` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '就诊号（HIS编码）',
  `patient_id` bigint NOT NULL COMMENT '患者ID',
  `patient_his_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '患者HIS主键',
  `patient_no` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '患者编码',
  `patient_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '患者名称',
  `dept_id` bigint NOT NULL COMMENT '科室ID',
  `dept_his_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '科室HIS主键',
  `dept_name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '科室名称（冗余）',
  `bed_no` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '床位号',
  `visit_type` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '就诊类型(10住院,0103急诊留观)',
  `admission_datetime` datetime NOT NULL COMMENT '入院时间',
  `discharge_datetime` datetime DEFAULT NULL COMMENT '出院时间',
  `admission_count` int DEFAULT '1' COMMENT '住院次数',
  `doctor_id` bigint DEFAULT NULL COMMENT '主治医生ID',
  `doctor_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '主治医生姓名',
  `nurse_level` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '护理级别（特级/一级/二级/三级）',
  `nurse_level_code` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '护理等级编码（00特级/01一级/02二级/03三级）',
  `nurse_area_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '病区HIS主键',
  `nurse_area_code` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '病区编码',
  `nurse_area_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '病区名称',
  `patient_status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '患者状态（在院/出院/转科/死亡）',
  `is_critical` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否危重患者',
  `sync_time` datetime NOT NULL COMMENT '最后同步时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
